    85→    pub fn new(store: EventStore, initial_filter: Option<String>) -> Self {
    86→        let mut state = AppState {
    87→            filtered_indices: store.all_indices(),
    88→            selected_event: if store.is_empty() { None } else { Some(0) },
    89→            filter: None,
    90→            filter_text: String::new(),
    91→            store,
    92→        };
